def validate_url(url):
    """
    Validate that a URL is from an allowed source.
    Prevents downloading from arbitrary/malicious URLs.
    """
    if not url.startswith("https://"):
        raise ValueError(f"Only HTTPS URLs are allowed. Got: {url}")

    if not any(url.startswith(prefix) for prefix in ALLOWED_URL_PREFIXES):
        raise ValueError(
            f"URL not from an allowed source: {url}\n"
            f"Allowed prefixes: {ALLOWED_URL_PREFIXES}"
        )

    return True


def verify_file_integrity(filepath, expected_sha256):
    """
    Verify the SHA-256 checksum of a downloaded file.
    Prevents use of tampered or corrupted files.
    """
    sha256_hash = hashlib.sha256()
    with open(filepath, "rb") as f:
        for chunk in iter(lambda: f.read(8192), b""):
            sha256_hash.update(chunk)

    actual_hash = sha256_hash.hexdigest()
    if actual_hash != expected_sha256:
        raise ValueError(
            f"Integrity check failed for {filepath}!\n"
            f"Expected SHA-256: {expected_sha256}\n"
            f"Actual SHA-256:   {actual_hash}\n"
            "The file may have been tampered with."
        )

    logger.info(f"Integrity verified for {filepath}")
    return True


def create_secure_ssl_context():
    """
    Create a secure SSL context for HTTPS downloads.
    Enforces certificate verification and modern TLS.
    """
    ctx = ssl.create_default_context()
    # Enforce TLS 1.2 or higher
    ctx.minimum_version = ssl.TLSVersion.TLSv1_2
    # Verify certificates
    ctx.check_hostname = True
    ctx.verify_mode = ssl.CERT_REQUIRED
    return ctx


def download_resource(url, target_path, expected_sha256, ssl_context=None):
    """
    Securely download a resource with integrity verification.
    Downloads to a temporary file first, verifies, then moves to target.
    """
    validate_url(url)

    if ssl_context is None:
        ssl_context = create_secure_ssl_context()

    target_path = Path(target_path)
    target_path.parent.mkdir(parents=True, exist_ok=True)

    # Download to a temporary file in the same directory (for atomic rename)
    fd, tmp_path = tempfile.mkstemp(
        dir=str(target_path.parent),
        prefix=f".{target_path.name}.",
        suffix=".tmp"
    )

    try:
        logger.info(f"Downloading {url} ...")
        req = urllib.request.Request(
            url,
            headers={"User-Agent": f"{PACKAGE_NAME}-installer/{PACKAGE_VERSION}"}
        )

        with urllib.request.urlopen(req, context=ssl_context, timeout=60) as response:
            # Check response status
            if response.status != 200:
                raise RuntimeError(
                    f"Download failed with status {response.status}: {url}"
                )

            # Limit download size to prevent resource exhaustion (50 MB max)
            max_size = 50 * 1024 * 1024
            total_read = 0

            with os.fdopen(fd, 'wb') as out_file:
                while True:
                    chunk = response.read(8192)
                    if not chunk:
                        break
                    total_read += len(chunk)
                    if total_read > max_size:
                        raise RuntimeError(
                            f"Download exceeds maximum allowed size ({max_size} bytes): {url}"
                        )
                    out_file.write(chunk)
                fd = None  # fd is now owned by the context manager

        # Verify integrity before moving to final location
        verify_file_integrity(tmp_path, expected_sha256)

        # Atomic rename (on same filesystem)
        os.replace(tmp_path, str(target_path))
        logger.info(f"Successfully downloaded and verified: {target_path}")

    except Exception:
        # Clean up temporary file on failure
        if fd is not None:
            os.close(fd)
        if os.path.exists(tmp_path):
            os.unlink(tmp_path)
        raise


