def _setup_env_unix(env_vars, config_dir):
    """
    Set up environment variables for Unix-like systems.
    Creates a sourceable env file.
    """
    env_file = config_dir / "env.sh"

    lines = [
        f"#!/bin/sh",
        f"# Environment variables for {PACKAGE_NAME}",
        f"# Source this file: . {env_file}",
        f"# Generated by {PACKAGE_NAME} installer v{PACKAGE_VERSION}",
        "",
    ]

    for key, value in env_vars.items():
        # Sanitize values to prevent shell injection
        safe_value = value.replace("'", "'\\''")
        lines.append(f"export {key}='{safe_value}'")

    env_file.write_text("\n".join(lines) + "\n")

    if platform.system() != "Windows":
        os.chmod(str(env_file), 0o600)

    logger.info(f"Environment file created: {env_file}")
    logger.info(f"To load environment variables, run: source {env_file}")

    # Also create a JSON version for programmatic access
    env_json_file = config_dir / "env.json"
    env_json_file.write_text(json.dumps(env_vars, indent=2) + "\n")
    if platform.system() != "Windows":
        os.chmod(str(env_json_file), 0o600)


def _setup_env_windows(env_vars):
    """
    Set up environment variables for Windows.
    Sets user-level environment variables via setx.
    """
    for key, value in env_vars.items():
        try:
            # Use setx to set user-level environment variables
            # setx has a 1024 character limit for values
            if len(value) > 1024:
                logger.warning(
                    f"Value for {key} exceeds 1024 chars, skipping setx. "
                    "Set manually in System Properties."
                )
                continue

            subprocess.run(
                ["setx", key, value],
                check=True,
                capture_output=True,
                text=True,
                timeout=30,
            )
            logger.info(f"Set environment variable: {key}")
        except (subprocess.CalledProcessError, FileNotFoundError) as e:
            logger.warning(f"Could not set {key} via setx: {e}")
            logger.info(f"Please set manually: {key}={value}")


